// kernel side
struct {
    __uint(type, BPF_MAP_TYPE_ARRAY);
    __uint(max_entries, 1);
    __type(key, __u32);
    __type(value, __u64);
} drop_count SEC(".maps");

// inside the XDP program, on each dropped packet:
__u32 key = 0;
__u64 *val = bpf_map_lookup_elem(&drop_count, &key);
if (val) __sync_fetch_and_add(val, 1);

# Rough path of an incoming packet:
NIC -> [XDP hook] -> sk_buff allocation -> tc ingress -> netfilter -> socket

# An XDP program returns a verdict before most of that happens:
SEC("xdp")
int drop_bad(struct xdp_md *ctx) {
    // ... inspect raw packet bytes ...
    return XDP_DROP;   // or XDP_PASS, XDP_TX, XDP_REDIRECT
}

// reading a kernel struct field directly bakes in an offset:
struct task_struct *task = (void *)bpf_get_current_task();
pid_t ppid = task->real_parent->tgid;   // offset differs per kernel

// CO-RE way: let the loader fix the offset at load time
pid_t ppid = BPF_CORE_READ(task, real_parent, tgid);

// current: one shared value, every CPU races on it
struct {
    __uint(type, BPF_MAP_TYPE_HASH);
    __type(key, __u32);
    __type(value, __u64);
} bytes SEC(".maps");

// hot path, all CPUs hitting the same entry:
__sync_fetch_and_add(val, pkt_len);

// eBPF LSM program attached to the file_open hook
SEC("lsm/file_open")
int BPF_PROG(block_shadow, struct file *file) {
    // ... match the path and the calling process ...
    if (is_blocked_path(file))
        return -EPERM;   // non-zero return DENIES the operation
    return 0;            // allow
}

SEC("xdp")
int parse(struct xdp_md *ctx) {
    void *data     = (void *)(long)ctx->data;
    void *data_end = (void *)(long)ctx->data_end;
    struct ethhdr *eth = data;

    // verifier: invalid access to packet, off=0 size=14 ...
    if (eth->h_proto == bpf_htons(ETH_P_IP))
        return XDP_PASS;
    return XDP_DROP;
}

// current: per-CPU perf buffer, can drop per CPU and reorder globally
struct {
    __uint(type, BPF_MAP_TYPE_PERF_EVENT_ARRAY);
} events SEC(".maps");
bpf_perf_event_output(ctx, &events, BPF_F_CURRENT_CPU, &e, sizeof(e));

// candidate: single shared ring buffer
struct {
    __uint(type, BPF_MAP_TYPE_RINGBUF);
    __uint(max_entries, 256 * 1024);
} rb SEC(".maps");
bpf_ringbuf_output(&rb, &e, sizeof(e), 0);
